module shift_reg8bit
(
  input  [7:0] data_in,
  input  clk,
  input  load,
  output serial_out
);

reg [7:0] obf_shift_reg;

always @(posedge clk) begin
  if (load)
    obf_shift_reg <= data_in;
  else
    obf_shift_reg <= {1'b0, obf_shift_reg[7:1]};
end

assign serial_out = obf_shift_reg[0];

endmodule
